      "path": "src/cli.ts",
      "content": "import { TaskStore } from './store';
import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';
import { randomUUID } from 'crypto';

declare const require: any;
declare const process: any;

const fs = require('node:fs');
const argv = process.argv.slice(2);
const cmd = argv[0];
const dataPathIndex = argv.indexOf('--data');
const dataPath = dataPathIndex !== -1 ? argv[dataPathIndex + 1] : null;

if (cmd === '--help') {
  console.log(`
Usage:
  list --data <path>
  add <title> --data <path>
  done <id> --data <path>
  remove <id> --data <path>
  --help
`);
  process.exit(0);
}

if (!dataPath) {
  console.error('Error: --data <path> is required');
  process.exit(1);
}

const store = new TaskStore(dataPath);

switch (cmd) {
  case 'list': {
    const tasks = store.list();
    console.log(JSON.stringify({ ok: true, tasks }));
    break;
  }
  case 'add': {
    const title = argv[1];
    if (!title) {
      console.error('Error: Title is required for add command');
      process.exit(1);
    }
    const task = store.add(title);
    console.log(JSON.stringify({ ok: true, task }));
    break;
  }
  case 'done': {
    const id = argv[1];
    if (!id) {
      console.error('Error: ID is required for done command');
      process.exit(1);
    }
    const task = store.done(id);
    console.log(JSON.stringify({ ok: true, task }));
    break;
  }
  case 'remove': {
    const id = argv[1];
    if (!id) {
      console.error('Error: ID is required for remove command');
      process.exit(1);
    }
    const task = store.remove(id);
    console.log(JSON.stringify({ ok: true, task }));
    break;
  }
  default: {
    console.error('Error: Unknown command');
    process.exit(1);
  }
}
"
